// src/pages/ngo/user/ListFundsPage.jsx
import { useState } from "react";
import PageHeader   from "../../../components/shared/PageHeader";
import DataTable    from "../../../components/shared/DataTable";
import Badge        from "../../../components/shared/Badge";
import { funds }    from "../../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";

export default function ListFundsPage() {
  const [tab, setTab] = useState("all");
  const filtered = tab === "all" ? funds : funds.filter((f) => f.status === tab);

  return (
    <div>
      <PageHeader title="Funds by NGO" desc="All fundraising campaigns for your organization" />

      <div className="tabs">
        {["all","open","closed"].map((t) => (
          <div key={t} className={`tab ${tab===t?"active":""}`} onClick={() => setTab(t)}>
            {t[0].toUpperCase() + t.slice(1)}
          </div>
        ))}
      </div>

      <div className="card">
        <DataTable
          columns={[
            { key:"id",      label:"ID",        mono:true },
            { key:"name",    label:"Fund Name"            },
            { key:"target",  label:"Target",   render:(r) => <span className="text-gold">{fmt(r.target)}</span> },
            { key:"raised",  label:"Raised",   render:(r) => fmt(r.raised) },
            { key:"donors",  label:"Donors"               },
            { key:"created", label:"Created",  mono:true  },
            { key:"status",  label:"Status",   render:(r) => <Badge type={r.status==="open"?"green":"red"}>{r.status}</Badge> },
          ]}
          data={filtered}
        />
      </div>
    </div>
  );
}
